constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = -INFINITY;
for (uint j = 0; j < W; ++j) {
    float s = (float)scores[j];
    max_s = (s > max_s) ? s : max_s;
}

float denom = 0.0f;
float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    denom += w;
    acc += w * (float)values[j * D + d_idx];
}
out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = -INFINITY;
float denom = 0.0f;
float acc = 0.0f;

// First pass: find max
for (uint j = 0; j < W; ++j) {
    float s = (float)scores[j];
    max_s = (s > max_s) ? s : max_s;
}

// Second pass: fused exp-sum-weighted-accumulate
for (uint j = 0; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    denom += w;
    acc += w * (float)values[j * D + d_idx];
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = -INFINITY;
for (uint j = 0; j < 64; j += 4) {
    float s0 = (float)scores[j];
    float s1 = (float)scores[j + 1];
    float s2 = (float)scores[j + 2];
    float s3 = (float)scores[j + 3];
    max_s = metal::max(metal::max(metal::max(max_s, s0), s1), metal::max(s2, s3));
}
max_s = metal::max(max_s, (float)scores[64]);

float denom = 0.0f;
float acc = 0.0f;
for (uint j = 0; j < 64; j += 4) {
    float w0 = metal::exp((float)scores[j] - max_s);
    float w1 = metal::exp((float)scores[j + 1] - max_s);
    float w2 = metal::exp((float)scores[j + 2] - max_s);
    float w3 = metal::exp((float)scores[j + 3] - max_s);
    denom += w0 + w1 + w2 + w3;
    acc += w0 * (float)values[j * D + d_idx];
    acc += w1 * (float)values[(j + 1) * D + d_idx];
    acc += w2 * (float)values[(j + 2) * D + d_idx];
    acc += w3 * (float)values[(j + 3) * D + d_idx];
}
float w_last = metal::exp((float)scores[64] - max_s);
denom += w_last;
acc += w_last * (float)values[64 * D + d_idx];

out[d_idx] = (T)(acc / denom);

