constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float scores_cache[W];
float max_s = -INFINITY;
for (uint j = 0; j < W; ++j) {
    scores_cache[j] = (float)scores[j];
    max_s = metal::max(max_s, scores_cache[j]);
}

float weights[W];
float denom = 0.0f;
for (uint j = 0; j < W; ++j) {
    weights[j] = metal::exp(scores_cache[j] - max_s);
    denom += weights[j];
}

float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    acc += weights[j] * (float)values[j * D + d_idx];
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
uint tid = thread_position_in_threadgroup.x;
if (d_idx >= D) return;

threadgroup float shared_scores[W];
if (tid < W) {
    shared_scores[tid] = (float)scores[tid];
}
if (tid + 128 < W) {
    shared_scores[tid + 128] = (float)scores[tid + 128];
}
threadgroup_barrier(mem_flags::mem_threadgroup);

float max_s = -INFINITY;
for (uint j = 0; j < W; ++j) {
    max_s = metal::max(max_s, shared_scores[j]);
}

float denom = 0.0f;
float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    float w = metal::exp(shared_scores[j] - max_s);
    denom += w;
    acc += w * (float)values[j * D + d_idx];
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = (float)scores[0];
float prefetch_val = (float)values[d_idx];
for (uint j = 1; j < W; ++j) {
    float s = (float)scores[j];
    float v = (float)values[j * D + d_idx];
    max_s = metal::max(max_s, s);
    (void)v; // Prefetch for later
}

float denom = 0.0f;
float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    float v = (float)values[j * D + d_idx];
    denom += w;
