out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

// Find max score
float max_s = (float)scores[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}

// Vectorized accumulation - process 4 consecutive rows at once
float denom = 0.0f;
float acc = 0.0f;
uint j = 0;
for (; j + 3 < W; j += 4) {
    float4 weights = float4(
        metal::exp((float)scores[j] - max_s),
        metal::exp((float)scores[j+1] - max_s),
        metal::exp((float)scores[j+2] - max_s),
        metal::exp((float)scores[j+3] - max_s)
    );
    float4 vals = float4(
        (float)values[j * D + d_idx],
        (float)values[(j+1) * D + d_idx],
        (float)values[(j+2) * D + d_idx],
        (float)values[(j+3) * D + d_idx]
    );
    denom += weights.x + weights.y + weights.z + weights.w;
    acc += dot(weights, vals);
}
// Tail
for (; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    denom += w;
    acc += w * (float)values[j * D + d_idx];
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
uint lane_id = thread_position_in_threadgroup.x;
if (d_idx >= D) return;

// SIMD-wide max reduction
float max_s = (float)scores[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}
max_s = simd_max(max_s);

// Compute with shared max
float denom = 0.0f;
float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    float v = (float)values[j * D + d_idx];
    denom += w;
    acc += w * v;
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
uint tid = thread_position_in_threadgroup.x;
uint tg_size = 64;
if (d_idx >= D) return;

threadgroup float shared_scores[W];
threadgroup float shared_max;

// First thread loads scores to shared memory
if (tid == 0) {
    for (uint j = 0; j < W; ++j) {
        shared_scores[j] = (float)scores[j];
    }
}
threadgroup_barrier(mem_flags::mem_threadgroup);

// Parallel max reduction
float local_max = shared_scores[0];
for (uint j = tid; j < W; j += tg_size) {
    local_max = metal::max(local_max, shared_scores[j]);
}
local_max = simd_max(local_max);
if (tid == 0) shared_max = local_max;
threadgroup_barrier(mem_flags::mem_threadgroup);

// Compute using shared max and scores
float denom = 0.0f;
float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    float w = metal::exp(shared_scores[j] - shared_max);
    float v = (float)values[j * D + d_idx];
    denom += w;
    acc += w * v;
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = (float)scores[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}

float denom = 0.0f;
float acc = 0.0f;
uint j = 0;
for (; j + 7 < W; j += 8) {
    float w0 = metal::exp((float)scores[j] - max_s);
    float w1 = metal::exp((float)scores[j+1] - max_s);
    float w2 = metal::exp((float)scores[j+2] - max_s);
    float w3 = metal::exp((float)scores[j+3] - max_s);
    float w4 = metal::exp((float)scores[j+4] - max_s);
    float w5 = metal::exp((float)scores[j+5] - max_s);
    float w6 = metal::exp((float)scores[j+6] - max_s);
    float w7 = metal::exp((float)scores[j+7] - max_s);

    float v0 = (float)values[j * D + d_idx];
    float v1 = (float)values[(j+1) * D + d_idx];
    float v2 = (float)values[(j+2) * D + d_idx];
    float v3 = (float)values[(j+3) * D + d_idx];
    float v4 = (float)values[(j+4) * D + d_idx];
    float v5 = (float)values[(j+5) * D + d_idx];
    float v6 = (float)values[(j+6) * D + d_idx];
    float v7 = (float)values[(j+7) * D + d_idx];

    denom += w0 + w1 + w2 + w3 + w4 + w5 + w6 + w7;
    acc += w0*v0 + w1*v1 + w2*v2 + w3*v3 + w4*v4 + w5*v5 + w6*v6 + w7*v7;
}
for (; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    float v = (float)values[j * D + d_idx];
    denom += w;
    acc += w * v;
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

// Prefetch all scores into registers
float s[65];
for (uint j = 0; j < W; ++j) {
    s[j] = (float)scores[j];
}

// Find max
float max_s = s[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, s[j]);
}

// Precompute all weights
float w[65];
float denom = 0.0f;
for (uint j = 0; j < W; ++j) {
    w[j] = metal::exp(s[j] - max_s);
    denom += w[j];
}

// Accumulate with precomputed weights
float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    acc += w[j] * (float)values[j * D + d_idx];
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
