    float v10 = (float)values[(j+10) * D + d_idx];
    float v11 = (float)values[(j+11) * D + d_idx];
    float v12 = (float)values[(j+12) * D + d_idx];
    float v13 = (float)values[(j+13) * D + d_idx];
    float v14 = (float)values[(j+14) * D + d_idx];
    float v15 = (float)values[(j+15) * D + d_idx];

    denom += w0 + w1 + w2 + w3 + w4 + w5 + w6 + w7 + w8 + w9 + w10 + w11 + w12 + w13 + w14 + w15;
    acc += w0*v0 + w1*v1 + w2*v2 + w3*v3 + w4*v4 + w5*v5 + w6*v6 + w7*v7 + w8*v8 + w9*v9 + w10*v10 + w11*v11 + w12*v12 + w13*v13 + w14*v14 + w15*v15;
}
for (; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    float v = (float)values[j * D + d_idx];
    denom += w;
    acc += w * v;
