out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = (float)scores[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}

float denom = 0.0f;
float acc = 0.0f;
uint j = 0;
for (; j + 7 < W; j += 8) {
    // Interleave exp with loads
    float w0 = metal::exp((float)scores[j] - max_s);
    float v0 = (float)values[j * D + d_idx];
    float w1 = metal::exp((float)scores[j+1] - max_s);
    float v1 = (float)values[(j+1) * D + d_idx];

    float w2 = metal::exp((float)scores[j+2] - max_s);
    float v2 = (float)values[(j+2) * D + d_idx];
    float w3 = metal::exp((float)scores[j+3] - max_s);
    float v3 = (float)values[(j+3) * D + d_idx];

    float w4 = metal::exp((float)scores[j+4] - max_s);
    float v4 = (float)values[(j+4) * D + d_idx];
    float w5 = metal::exp((float)scores[j+5] - max_s);
    float v5 = (float)values[(j+5) * D + d_idx];

    float w6 = metal::exp((float)scores[j+6] - max_s);
    float v6 = (float)values[(j+6) * D + d_idx];
    float w7 = metal::exp((float)scores[j+7] - max_s);
    float v7 = (float)values[(j+7) * D + d_idx];

    // Accumulate in pairs
    float sum_w01 = w0 + w1;
    float sum_w23 = w2 + w3;
    float sum_w45 = w4 + w5;
    float sum_w67 = w6 + w7;

    float acc01 = w0*v0 + w1*v1;
    float acc23 = w2*v2 + w3*v3;
    float acc45 = w4*v4 + w5*v5;
    float acc67 = w6*v6 + w7*v7;

    denom += sum_w01 + sum_w23 + sum_w45 + sum_w67;
    acc += acc01 + acc23 + acc45 + acc67;
}
for (; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    float v = (float)values[j * D + d_idx];
    denom += w;
    acc += w * v;
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x;
if (d_idx >= D) return;

float max_s = (float)scores[0];
for (uint j = 1; j < 33; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}
max_s = metal::simd_max(max_s);
for (uint j = 33; j < W; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}
max_s = metal::simd_max(max_s);

float denom = 0.0f;
float acc = 0.0f;
uint j = 0;
for (; j + 7 < W; j += 8) {
    float w0 = metal::exp((float)scores[j] - max_s);
    float w1 = metal::exp((float)scores[j+1] - max_s);
    float w2 = metal::exp((float)scores[j+2] - max_s);
    float w3 = metal::exp((float)scores[j+3] - max_s);
    float w4 = metal::exp((float)scores[j+4] - max_s);
    float w5 = metal::exp((float)scores[j+5] - max_s);
    float w6 = metal::exp((float)scores[j+6] - max_s);
    float w7 = metal::exp((float)scores[j+7] - max_s);

    float v0 = (float)values[j * D + d_idx];
    float v1 = (float)values[(j+1) * D + d_idx];
    float v2 = (float)values[(j+2) * D + d_idx];
    float v3 = (float)values[(j+3) * D + d_idx];
    float v4 = (float)values[(j+4) * D + d_idx];
    float v5 = (float)values[(j+5) * D + d_idx];
    float v6 = (float)values[(j+6) * D + d_idx];
    float v7 = (float)values[(j+7) * D + d_idx];

    denom += w0 + w1 + w2 + w3 + w4 + w5 + w6 + w7;
    acc += w0*v0 + w1*v1 + w2*v2 + w3*v3 + w4*v4 + w5*v5 + w6*v6 + w7*v7;
}
for (; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    float v = (float)values[j * D + d_idx];
    denom += w;
    acc += w * v;
}

out[d_idx] = (T)(acc / denom);

constexpr uint D = 128;
constexpr uint W = 65;
uint d_idx = thread_position_in_grid.x * 4;
if (d_idx >= D) return;

// Find max score across all threads using SIMD reduction
float max_s = (float)scores[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, (float)scores[j]);
}
max_s = metal::simd_max(max_s);

// Compute weights and accumulate using vectorized loads
float4 acc = float4(0.0f);
float denom = 0.0f;

for (uint j = 0; j < W; ++j) {
    float w = metal::exp((float)scores[j] - max_s);
    denom += w;

    float4 v = float4((float)values[j * D + d_idx],
                      (float)values[j * D + d_idx + 1],
                      (float)values[j * D + d_idx + 2],
                      (float)values[j * D + d_idx + 3]);
    acc += w * v;
}

float denom_inv = 1.0f / denom;
out[d_idx] = (T)(acc.x * denom_inv);
out[d_idx + 1] = (T)(acc.y * denom_inv);
out[d_idx + 2] = (T)(acc.z * denom_inv);
out[d_idx + 3] = (T)(acc.w * denom_inv);

constexpr uint D = 128;
constexpr uint W = 65;
threadgroup float s_scores[W];

uint tid = thread_position_in_threadgroup.x;
uint d_idx = thread_position_in_grid.x;

// Coalesced load of scores into shared memory
if (tid < W) {
    s_scores[tid] = (float)scores[tid];
}
threadgroup_barrier(mem_flags::mem_threadgroup);

if (d_idx >= D) return;

// Find max from shared memory
float max_s = s_scores[0];
for (uint j = 1; j < W; ++j) {
    max_s = metal::max(max_s, s_scores[j]);
}

// Compute weighted sum
float denom = 0.0f;
