    max_s = metal::max(max_s, (float)scores[j]);
}

// Compute weights and denominator with unrolled pairs
float denom = 0.0f;
float acc = 0.0f;

for (uint j = 0; j < 64; j += 2) {
    float w0 = metal::fast::exp((float)scores[j] - max_s);
    float w1 = metal::fast::exp((float)scores[j+1] - max_s);
    float v0 = (float)values[j * D + d_idx];
    float v1 = (float)values[(j+1) * D + d_idx];

    denom += w0 + w1;
    acc = metal::fma(w0, v0, acc);
    acc = metal::fma(w1, v1, acc);
}

// Tail element
